162	//
163	// _rank_filter() requires the allocation of memory.  If the allocation fails,
164	// the function returns -1.  Otherwise it returns 0.
165	//
166	template <typename T>
167	int _rank_filter(T *in_arr, int rank, int arr_len, int win_len, T *out_arr,
168	                  int mode, T cval, int origin) {
169	  int i, arr_len_thresh, lim = (win_len - 1) / 2 - origin;
170	  int lim2 = arr_len - lim;
171	  /* Note: `arr_len == 1` is the only case implemented here for `lim2 < 0`; the calling code */
172	  /* in _filters.py ensures that this function isn't called otherwise. xref gh-23293 for details. */
173	  if (lim2 < 0 && arr_len == 1) {
174	      switch (mode) {
175	          case REFLECT:
176	          case NEAREST:
177	          case WRAP:
178	          case MIRROR:
179	              out_arr[0] = in_arr[0];
180	              return 0;
181	          case CONSTANT:
182	              if (win_len == 1) {
183	                  out_arr[0] = in_arr[0];
184	              }
185	              else {
186	                  out_arr[0] = cval;
187	              }
188	              return 0;
189	      }
190	  }
191	  int offset;
192	  std::unique_ptr<Mediator> m;
193	  std::unique_ptr<T[]> data;
194	  try {
195	    m = std::make_unique<Mediator>(win_len, rank);
196	    data = std::unique_ptr<T[]>(new T[win_len]());
197	  } catch (std::bad_alloc&) {
198	    return -1;
199	  }
200	
201	  switch (mode) {
202	  case REFLECT:
203	    for (i = win_len - lim - 1; i > -1; i--) {
204	      MediatorInsert(data.get(), m.get(), in_arr[i]);
205	    }
206	    break;
207	  case CONSTANT:
208	    for (i = win_len - lim; i > 0; i--) {
209	      MediatorInsert(data.get(), m.get(), cval);
210	    }
211	    break;
212	  case NEAREST:
213	    for (i = win_len - lim; i > 0; i--) {
214	      MediatorInsert(data.get(), m.get(), in_arr[0]);
215	    }
216	    break;
217	  case MIRROR:
218	    for (i = win_len - lim; i > 0; i--) {
219	      MediatorInsert(data.get(), m.get(), in_arr[i]);
220	    }
221	    break;
222	  case WRAP:
223	    if (win_len % 2 == 0) {
224	        offset = 2;
225	    }
226	    else {
227	        offset = 0;
228	    }
229	    for (i = arr_len - lim - offset - 2 * origin; i < arr_len; i++) {
230	      MediatorInsert(data.get(), m.get(), in_arr[i]);
231	    }
232	    break;
233	  }
234	
235	  for (i = 0; i < lim; i++) {
236	    MediatorInsert(data.get(), m.get(), in_arr[i]);
237	  }
238	  for (i = lim; i < arr_len; i++) {
239	    MediatorInsert(data.get(), m.get(), in_arr[i]);
240	    out_arr[i - lim] = data[m->heap[0]];
241	  }
242	  switch (mode) {
243	  case REFLECT:
244	    arr_len_thresh = arr_len - 1;
245	    for (i = 0; i < lim; i++) {
246	      MediatorInsert(data.get(), m.get(), in_arr[arr_len_thresh - i]);
247	      out_arr[lim2 + i] = data[m->heap[0]];
248	    }
249	    break;
250	  case CONSTANT:
251	    for (i = 0; i < lim; i++) {
252	      MediatorInsert(data.get(), m.get(), cval);
253	      out_arr[lim2 + i] = data[m->heap[0]];
254	    }
255	    break;
256	  case NEAREST:
257	    arr_len_thresh = arr_len - 1;
258	    for (i = 0; i < lim; i++) {
259	      MediatorInsert(data.get(), m.get(), in_arr[arr_len_thresh]);
260	      out_arr[lim2 + i] = data[m->heap[0]];
261	    }
262	    break;
263	  case MIRROR:
264	    arr_len_thresh = arr_len - 2;
265	    for (i = 0; i < lim; i++) {
266	      MediatorInsert(data.get(), m.get(), in_arr[arr_len_thresh - i]);
267	      out_arr[lim2 + i] = data[m->heap[0]];
268	    }
269	    break;
270	  case WRAP:
271	    for (i = 0; i < lim; i++) {
272	      MediatorInsert(data.get(), m.get(), in_arr[i]);
273	      out_arr[lim2 + i] = data[m->heap[0]];
274	    }
275	    break;
276	  }
277	  return 0;
278	}
